--Write a SELECT statement that:--Returns BusinessEntityID--Calculates the employee’s age in years--Calculates the number of years worked in the company--Formats HireDate as yyyy-MM-dd--Returns only male employees hired after 2010SELECT BusinessEntityID, 	   DATEDIFF(YEAR, BirthDate, GETDATE()) AS Varsta,	   DATEDIFF(YEAR, HireDate, GETDATE()) AS AniInCompanie,	   FORMAT(HireDate, 'yyyy-MM-dd') AS DataAngajareFROM HumanResources.EmployeeWHERE YEAR(HireDate) >= 2010AND Gender = 'M'--Task--Write a SELECT statement that:--Returns ProductID--Returns the first 12 characters of Name--Replaces dashes (-) in ProductNumber with spaces--Creates a column PriceCategory:--"Premium" if ListPrice ≥ 1000--"Standard" otherwise--Returns only products that:--Are not discontinued--Contain the word "Road" in their nameSELECT ProductID,		LEFT(Name, 12),		REPLACE(ProductNumber, '-', ' '),		CASE			WHEN ListPrice >= 1000 THEN 'Premium'			ELSE 'Standard'		END AS PriceCategoryFROM Production.ProductWHERE Name LIKE '%Road%'AND DiscontinuedDate IS NULL--Task--Write a SELECT statement that:--Returns SalesOrderID--Converts OrderDate to VARCHAR--Shows "Not shipped" when ShipDate is NULL--Calculates the number of days between order and shipping--(use today’s date if not shipped)--Replaces NULL comments with "No comment"--Returns only online orders placed in 2012SELECT SalesOrderID,	CONVERT(varchar(10), OrderDate, 120) AS OrderDate,      CASE         WHEN ShipDate IS NULL THEN 'Not shipped'        ELSE ShipDate    END,    DATEDIFF(day, OrderDate, ISNULL(ShipDate, GETDATE())) AS DaysToShip,    ISNULL(Comment, 'No comment') AS CommentFROM Sales.SalesOrderHeaderWHERE OnlineOrderFlag = 1 AND YEAR(OrderDate) = 2012-- Task--Write a SELECT statement that:--Returns BusinessEntityID--Builds a FullName column using first and last name--Returns the length of the full name--Displays "Has middle name" or "No middle name" depending on MiddleName--Returns only people whose last name contains "son"SELECT BusinessEntityID,	   FirstName + ' ' + LastName AS FullName,	   LEN(FirstName + ' ' + LastName) AS NameLength,	   CASE		WHEN MiddleName IS NULL THEN 'No middle name'		ELSE 'Has middle name'	   ENDFROM Person.PersonWHERE LastName LIKE '%son%'--Task--Write a SELECT statement that:--Extracts year, month, and day from OrderDate--Reconstructs the date using DATEFROMPARTS--Displays the month name using CHOOSE--Categorizes orders as:--"High" if TotalDue ≥ 50000--"Medium" if between 10000 and 49999--"Low" otherwise--Returns only orders created in the last 3 yearsSELECT YEAR(OrderDate),		MONTH(OrderDate),		DAY(OrderDate),		DATEFROMPARTS(YEAR(OrderDate), MONTH(OrderDate), DAY(OrderDate)),		CHOOSE (MONTH(OrderDate), 'JANUARY', 'FEBRUARY', 'MARCH', 'APRIL',		'MAY', 'JUNE', 'JULY', 'AUGUST', 'SEPTEMBER', 'OCTOBER', 'NOVEMBER', 'DECEMBER'),		CASE			WHEN TotalDue >= 50000 THEN 'High'			WHEN TotalDue BETWEEN 10000 AND 49999 THEN 'Medium'			ELSE 'Low'		ENDFROM Purchasing.PurchaseOrderHeaderWHERE YEAR(OrderDate) >= YEAR(DATEADD(YEAR, -3, 2014))--Task--Write a SELECT statement that:--Calculates the employee’s exact age in years (adjust for birthday not yet reached this year)--Calculates full years of service (adjust for hire anniversary)--Categorizes tenure as:--"Junior": < 5 years--"Mid": 5–14 years--"Senior": ≥ 15 years--Returns "Salaried" or "Hourly" based on SalariedFlag--Returns only current employees older than 40SELECT IIF(GETDATE() < DATEFROMPARTS(YEAR(GETDATE()), MONTH(BirthDate), DAY(BirthDate)), 			DATEDIFF(YEAR, BirthDate, GETDATE()) - 1, DATEDIFF(YEAR, BirthDate, GETDATE())),	   IIF(GETDATE() < DATEFROMPARTS(YEAR(GETDATE()), MONTH(HireDate), DAY(HireDate)), 			DATEDIFF(YEAR, HireDate, GETDATE()) - 1, DATEDIFF(YEAR, HireDate, GETDATE())),	   CASE			WHEN IIF(GETDATE() < DATEFROMPARTS(YEAR(GETDATE()), MONTH(HireDate), DAY(HireDate)), 			DATEDIFF(YEAR, HireDate, GETDATE()) - 1, DATEDIFF(YEAR, HireDate, GETDATE())) < 5 			THEN 'Junior'			WHEN IIF(GETDATE() < DATEFROMPARTS(YEAR(GETDATE()), MONTH(HireDate), DAY(HireDate)), 			DATEDIFF(YEAR, HireDate, GETDATE()) - 1, DATEDIFF(YEAR, HireDate, GETDATE())) >= 15			THEN 'Senior'			ELSE 'Mid'		END,		CASE WHEN SalariedFlag = 1 THEN 'Salaried' ELSE 'Hourly' ENDFROM HumanResources.EmployeeWHERE IIF(GETDATE() < DATEFROMPARTS(YEAR(GETDATE()), MONTH(BirthDate), DAY(BirthDate)), 			DATEDIFF(YEAR, BirthDate, GETDATE()) - 1, DATEDIFF(YEAR, BirthDate, GETDATE())) >=40--Task--Write a SELECT statement that:--Builds a normalized full name:--Removes extra spaces--Ignores NULL middle names--Displays the total character count of the normalized name--Classifies names as "Short" (< 15 chars) or "Long"--Replaces NULL titles with "N/A"--Returns only people whose last name ends with "ez" or "son"SELECT CONCAT(FirstName, ' ', MiddleName + ' ', LastName) AS FullName,		LEN(CONCAT(FirstName, ' ', MiddleName + ' ', LastName)) AS NameLength,		CASE 			WHEN LEN(CONCAT(FirstName, ' ', MiddleName + ' ', LastName)) < 15 THEN 'Short'			ELSE 'Long'		END AS NameClass,		ISNULL(Title, 'N/A') AS TitleFROM Person.PersonWHERE LastName LIKE '%ez'OR LastName LIKE '%son'--Calculates WorkLifeBalanceScore using the following rules:--Start from a base score of 100--Subtract 1 point for each year of service--Subtract 2 points if the employee is salaried--Subtract 10 points if VacationHours < 20--Subtract 10 points if SickLeaveHours < 30--The score must not go below 0--Classifies WorkLifeBalanceLevel based on the score:--"Poor": score < 40--"Moderate": 40–69--"Good": ≥ 70--Displays WorkloadRisk as:--"Critical" if--Current employee--Salaried--Years of service ≥ 15--VacationHours < 15--SickLeaveHours < 20--"Warning" if--Current employee--(VacationHours < 30 OR SickLeaveHours < 40)--"Normal" otherwise--Displays RetentionFlag as:--"High value" if--Years of service ≥ 20--OR employee is older than 55--"Standard value" otherwise--Returns only current employees over 35select		BusinessEntityID,	HireDate,	SalariedFlag,	VacationHours,	SickLeaveHours,	datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end as YrsInCo,	--1.Start from a base score of 100--Subtract 1 point for each year of service--Subtract 2 points if the employee is salaried--Subtract 10 points if VacationHours < 20--Subtract 10 points if SickLeaveHours < 30--The score must not go below 0	iif(		100-(		datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end		+			iif(SalariedFlag = 1, 2, 0)		+		iif(VacationHours<20, 10, 0)		+		iif(SickLeaveHours<30,10,0)		) > 0,		100-(		datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end		+			iif(SalariedFlag = 1, 2, 0)		+		iif(VacationHours<20, 10, 0)		+		iif(SickLeaveHours<30,10,0)		),		0	) as WorkLifeBalanceScore,	--2.Classifies WorkLifeBalanceLevel based on the score:--"Poor": score < 40--"Moderate": 40–69--"Good": ≥ 70	case		when iif(			100-(			datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end			+				iif(SalariedFlag = 1, 2, 0)			+			iif(VacationHours<20, 10, 0)			+			iif(SickLeaveHours<30,10,0)			) > 0,			100-(			datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end			+				iif(SalariedFlag = 1, 2, 0)			+			iif(VacationHours<20, 10, 0)			+			iif(SickLeaveHours<30,10,0)			),			0			) < 40		then 'Poor'		when iif(			100-(			datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end			+				iif(SalariedFlag = 1, 2, 0)			+			iif(VacationHours<20, 10, 0)			+			iif(SickLeaveHours<30,10,0)			) > 0,			100-(			datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end			+				iif(SalariedFlag = 1, 2, 0)			+			iif(VacationHours<20, 10, 0)			+			iif(SickLeaveHours<30,10,0)			),			0			) between 40 and 69		then 'Moderate'		else 'Good'	end as WorkLifeBalanceLevel,	--3.Displays WorkloadRisk as:--"Critical" if--Current employee--Salaried--Years of service ≥ 15--VacationHours < 15--SickLeaveHours < 20--"Warning" if--Current employee--(VacationHours < 30 OR SickLeaveHours < 40)--"Normal" otherwise	case		when SalariedFlag = 1 			and datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end >= 15			and VacationHours < 15			and SickLeaveHours < 20		then 'Critical'		when VacationHours < 30 or SickLeaveHours < 40 then 'Warning'		else 'Normal'	end as WorkloadRisk,	--4.Displays RetentionFlag as:--"High value" if--Years of service ≥ 20--OR employee is older than 55--"Standard value" otherwise--Where Rule: Returns only current employees over 35	case		when datediff(year,HireDate,getdate()) - case when datefromparts(year(getdate()),month(HireDate),day(HireDate)) > getdate() then 1 else 0 end >= 20		or DATEDIFF(YEAR,BirthDate,GETDATE()) - case when DATEFROMPARTS(Year(getdate()),month(BirthDate),Day(BirthDate)) > GETDATE() then 1 else 0 end > 55		then 'High Value'		else 'Standard Value'	end as RetentionFlagfrom HumanResources.Employeewhere DATEDIFF(YEAR,BirthDate,GETDATE()) - case when DATEFROMPARTS(Year(getdate()),month(BirthDate),Day(BirthDate)) > GETDATE() then 1 else 0 end > 35